			bn_rand_mod(a, b);
			if (eb_curve_opt_a() == RLC_ZERO) {
				BENCH_ADD((len = RLC_FB_BITS + 8, bn_rec_tnaf(tnaf, &len, a, -1, RLC_FB_BITS, 4)));
