#endif /* WITH_EP && EP_KBLTZ */

	bn_free(a);
	bn_free(b);
	bn_free(c);
	for (int j = 0; j < 3; j++) {
		bn_free(d[j]);
		bn_free(e[j]);
	}
	crt_free(crt);
}

code_before_change:
static void benaloh(void) {
	bdpe_t pub, prv;
	dig_t in, new;
	uint8_t out[RLC_BN_BITS / 8 + 1];
	size_t out_len;

	bdpe_null(pub);
	bdpe_null(prv);

	bdpe_new(pub);
	bdpe_new(prv);

