void ep4_map(ep4_t p, const uint8_t *msg, int len) {
	bn_t x;
	fp4_t t0;
	uint8_t digest[RLC_MD_LEN];

	bn_null(x);
	fp4_null(t0);

	RLC_TRY {
		bn_new(x);
		fp4_new(t0);

